options.getOption:
const series = context.panel.data.series;
if (!series || !series.length) return {};

const frame = series[0];
const timeField = frame.fields.find(f => f.type === 'time');
const valueField = frame.fields.find(f => f.type === 'number');
if (!timeField || !valueField) return {};

const days = {};
for (let i = 0; i < timeField.values.length; i++) {
  const t = new Date(timeField.values[i]);
  const dd = String(t.getDate()).padStart(2, '0');
  const mm = String(t.getMonth() + 1).padStart(2, '0');
  const day = dd + '/' + mm;
  const hour = t.getHours() + t.getMinutes() / 60;
  if (!days[day]) days[day] = [];
  days[day].push([hour, valueField.values[i]]);
}

const bands = {
  silent: true,
  data: [
    [{ yAxis: 0, itemStyle: { color: 'rgba(196,22,42,0.15)' } }, { yAxis: 3.0 }],
    [{ yAxis: 3.0, itemStyle: { color: 'rgba(255,60,60,0.12)' } }, { yAxis: 3.9 }],
    [{ yAxis: 3.9, itemStyle: { color: 'rgba(55,135,45,0.12)' } }, { yAxis: 10.0 }],
    [{ yAxis: 10.0, itemStyle: { color: 'rgba(255,152,48,0.15)' } }, { yAxis: 13.9 }],
    [{ yAxis: 13.9, itemStyle: { color: 'rgba(196,22,42,0.15)' } }, { yAxis: 21 }]
  ]
};

const dayEntries = Object.entries(days).sort();
const chartSeries = dayEntries.map(([day, points], idx) => ({
  name: day,
  type: 'scatter',
  data: points,
  symbolSize: 3,
  markArea: idx === 0 ? bands : undefined
}));

return {
  backgroundColor: 'transparent',
  grid: { left: 40, right: 100, top: 20, bottom: 30 },
  xAxis: {
    type: 'value',
    min: 0,
    max: 24,
    splitLine: { show: false },
    axisLabel: {
      formatter: function(v) {
        return String(Math.floor(v)).padStart(2,'0') + ':00';
      }
    }
  },
  yAxis: {
    type: 'value',
    min: 0,
    max: 21,
    splitLine: { show: false }
  },
  legend: {
    show: true,
    orient: 'vertical',
    right: 10,
    top: 20,
    textStyle: { color: '#ccc' }
  },
  tooltip: {
    trigger: 'item',
    formatter: function(p) {
      var h = Math.floor(p.value[0]);
      var m = Math.round((p.value[0] - h) * 60);
      return p.seriesName + '<br/>' +
        String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') +
        ' \u2014 ' + p.value[1].toFixed(1) + ' mmol/L';
    }
  },
  series: chartSeries
};
